// Devolve a lista de abas para o Agente escolher.
// Aba 01 = SKUs + consumo diário; Aba 02 = lead times; Abas 03-60 = part numbers por SKU.
const abas = ($input.first().json.sheets || []).map(s => s.properties.title);
return [{
  json: {
    aviso_para_a_ia: "Você não informou o nome da aba. Estas são as abas disponíveis. Chame a ferramenta de novo passando um destes nomes em 'nome_do_separador'. Lembre: a primeira aba traz os SKUs e o consumo diário médio; a segunda traz os lead times; as demais (uma por SKU) trazem os part numbers detalhados.",
    abas_disponiveis: abas
  }
}];

// Filtra as linhas da aba pelo termo enviado pelo Agente (código SKU, part number ou descrição).
const trigger = $('Execute Workflow Trigger').first().json;
const termoBusca = (trigger.termo_de_pesquisa || '').toLowerCase().trim();

// Termos genéricos que a IA costuma inventar: ignoramos o filtro e devolvemos amostra.
const termosGenericos = ['todos', 'todas', 'tudo', 'geral', 'analise', 'análise', 'relatorio', 'relatório', 'lista', 'listar'];

if (!termoBusca || termosGenericos.includes(termoBusca)) {
  // Sem filtro útil: devolve até 200 linhas da aba para a IA analisar.
  return $input.all().slice(0, 200);
}

const resultados = [];
for (const item of $input.all()) {
  const linhaTexto = JSON.stringify(item.json).toLowerCase();
  if (linhaTexto.includes(termoBusca)) resultados.push(item);
}

// Devolve no máximo 100 correspondências.
return resultados.slice(0, 100);
